const body = $input.first().json.body || $input.first().json;
const message = body.message || body.query || '';
const customerId = body.customer_id || body.customerId || null;
const customerGroup = body.customer_group || body.customerGroup || 'B2C_Retail';
const isAdmin = body.is_admin || body.isAdmin || false;
const image = body.image || null;
const tenantContext = body.tenant_context || null;

const stopWords = ['bir','bu','şu','ve','ile','için','var','mı','mi','mu','mü','ne','nasıl','kaç','da','de','den','dan','nedir','olan'];
const words = message.toLowerCase()
  .replace(/[^a-zA-ZğüşıöçĞÜŞİÖÇ0-9\s]/g, '')
  .split(/\s+/)
  .filter(w => w.length > 2 && !stopWords.includes(w));

let intent = 'general';
const msg = message.toLowerCase();
if (/stok|envanter|kaç\s*(adet|tane)|mevcut|kaldı/i.test(msg)) intent = 'inventory_check';
else if (/sipariş|kargo|takip|nerede|teslimat/i.test(msg)) intent = 'product_search';
else if (/ürün|fiyat|ara|bul|var\s*mı|satıyor/i.test(msg)) intent = 'product_search';

return [{ json: {
  message, customer_id: customerId, customer_group: customerGroup,
  is_admin: isAdmin, image, search_term: words.join(' '),
  tenant_context: tenantContext,
  intent, keywords: words, retry_count: 0, max_retries: 3,
  validation_errors: [], timestamp: new Date().toISOString()
}}];

const intentData = $('1. Extract Intent').first().json;
const dbRaw = $('2. Query DB (Ground Truth)').first().json;

let ctx = { products: [], product_ids: [], variant_ids: [], price_map: {}, stock_map: {} };
try {
  ctx = typeof dbRaw.context === 'string' ? JSON.parse(dbRaw.context) : dbRaw.context || ctx;
} catch(e) {}

const lines = [];
lines.push('=== VERİTABANI BAĞLAMI (GROUND TRUTH) ===');
lines.push('Aşağıdaki veriler PostgreSQL veritabanından çekilmiştir. SADECE bu verilere dayanarak cevap ver.');
lines.push('Veritabanında olmayan ürün, fiyat veya stok bilgisi UYDURMA.');
lines.push('Eğer eşleşme yoksa "Bu ürün katalogumuzda bulunmuyor" de.');
lines.push('');

if (ctx.products && ctx.products.length > 0) {
  lines.push('── ÜRÜNLER ──');
  ctx.products.forEach(p => {
    const price = p.price_amount ? `${(p.price_amount / 100).toFixed(2)} ${p.currency_code || 'TRY'}` : 'Fiyat yok';
    const stock = p.available !== undefined ? `Stok: ${p.available}` : 'Stok bilgisi yok';
    lines.push(`• [${p.product_id}] ${p.title} | Varyant: ${p.variant_title || '-'} | SKU: ${p.sku || 'N/A'} | ${price} | ${stock}`);
  });
} else {
  lines.push('── EŞLEŞEN ÜRÜN YOK ──');
}

const retryCount = intentData.retry_count || 0;
const prevErrors = intentData.validation_errors || [];
if (retryCount > 0 && prevErrors.length > 0) {
  lines.push('');
  lines.push('⚠️ ÖNCEKİ YANIT REDDEDİLDİ. HATALAR:');
  prevErrors.forEach(e => lines.push(`  ✗ ${e}`));
  lines.push('BU HATALARI DÜZELTECEĞİM. Sadece gerçek veritabanı verilerine dayanacağım.');
}

lines.push('');
lines.push('=== YANITINI JSON FORMATINDA VER ===');
lines.push('Format: {"response": "...", "mentioned_product_ids": [...], "mentioned_prices": [{"variant_id": "...", "price": ..., "currency": "TRY"}]}');

return [{ json: {
  grounding_context: lines.join('\n'),
  tenant_context: intentData.tenant_context,
  original_message: intentData.message,
  customer_id: intentData.customer_id,
  customer_group: intentData.customer_group,
  is_admin: intentData.is_admin,
  intent: intentData.intent,
  search_term: intentData.search_term,
  retry_count: retryCount,
  max_retries: intentData.max_retries || 3,
  db_product_ids: ctx.product_ids || [],
  db_variant_ids: ctx.variant_ids || [],
  db_price_map: ctx.price_map || {},
  db_stock_map: ctx.stock_map || {},
  product_count: (ctx.products || []).length
}}];

// ══════════════════════════════════════════════
// VALIDATION CHECK — Hallucination Killer Core
// ══════════════════════════════════════════════
const contextData = $('3. Build Grounding Context').first().json;
const aiRawOutput = $('4. AI Agent (Gemini)').first().json.output || $('4. AI Agent (Gemini)').first().json.text || '';
const retryCount = contextData.retry_count || 0;
const maxRetries = contextData.max_retries || 3;

const errors = [];
let parsed = null;
let userResponse = '';
let mentionedProductIds = [];
let mentionedPrices = [];

// ── CHECK 1: JSON Format Geçerli mi? ──
try {
  // AI bazen markdown code block ile sarar
  let cleaned = aiRawOutput.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  // Bazen sadece metin döner, JSON aramayı dene
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    parsed = JSON.parse(jsonMatch[0]);
    userResponse = parsed.response || '';
    mentionedProductIds = parsed.mentioned_product_ids || [];
    mentionedPrices = parsed.mentioned_prices || [];
  } else {
    // JSON bulunamadı — düz metin olarak kabul et
    userResponse = cleaned;
    // JSON zorunlu değilse bu bir hata değil, ama grounding kontrolü zayıflar
    errors.push('JSON_FORMAT_INVALID: AI yanıtı geçerli JSON formatında değil. structured output bekleniyor.');
  }
} catch (e) {
  errors.push(`JSON_PARSE_ERROR: AI yanıtı parse edilemedi: ${e.message}`);
  userResponse = aiRawOutput; // fallback
}

// ── CHECK 2: Bahsedilen Ürün ID'leri DB'de var mı? ──
if (mentionedProductIds.length > 0) {
  const dbProductIds = new Set(contextData.db_product_ids || []);
  const phantomIds = mentionedProductIds.filter(id => !dbProductIds.has(id));
  if (phantomIds.length > 0) {
    errors.push(`PHANTOM_PRODUCT: Veritabanında olmayan ürün ID\'leri referans edildi: ${phantomIds.join(', ')}. Bu ID\'ler gerçek değil, UYDURMA.`);
  }
}

// ── CHECK 3: Fiyat Bilgisi Doğru mu? ──
if (mentionedPrices.length > 0) {
  const dbPriceMap = contextData.db_price_map || {};
  for (const mp of mentionedPrices) {
    const dbPrice = dbPriceMap[mp.variant_id];
    if (dbPrice === undefined) {
      errors.push(`PHANTOM_PRICE: variant_id=${mp.variant_id} için veritabanında fiyat bulunamadı. Bu fiyat uydurma olabilir.`);
    } else {
      // Fiyat tolerance: %1 sapma kabul edilebilir (yuvarlama farkı)
      const tolerance = dbPrice * 0.01;
      const aiPrice = mp.price;
      if (Math.abs(aiPrice - dbPrice) > tolerance) {
        errors.push(`PRICE_MISMATCH: variant_id=${mp.variant_id} için DB fiyatı=${dbPrice} ama AI fiyatı=${aiPrice}. Doğru fiyat kullanılmalı.`);
      }
    }
  }
}

// ── CHECK 4: Halüsinasyon Kelime Taraması ──
const hallucMarkers = [
  /\bindirim(?:li|de)?\b/i, /kampanya/i, /ücretsiz kargo/i, /taksit/i
];
const dbContext = contextData.grounding_context || '';
for (const marker of hallucMarkers) {
  if (marker.test(userResponse) && !marker.test(dbContext)) {
    const matched = userResponse.match(marker);
    errors.push(`HALLUCINATION_SUSPECT: "${matched?.[0]}" ifadesi yanıtta var ama veritabanı bağlamında yok. Gerçek mi kontrol edilmeli.`);
  }
}

// ── KARAR ──
const isValid = errors.length === 0;
const shouldRetry = !isValid && retryCount < maxRetries;

return [{ json: {
  is_valid: isValid,
  should_retry: shouldRetry,
  errors,
  error_count: errors.length,
  retry_count: retryCount,
  max_retries: maxRetries,
  ai_response: userResponse,
  raw_output: aiRawOutput,
  mentioned_product_ids: mentionedProductIds,
  mentioned_prices: mentionedPrices,
  // Pass-through for retry loop
  original_message: contextData.original_message,
  customer_id: contextData.customer_id,
  customer_group: contextData.customer_group,
  is_admin: contextData.is_admin,
  intent: contextData.intent,
  search_term: contextData.search_term,
  db_product_ids: contextData.db_product_ids,
  db_variant_ids: contextData.db_variant_ids,
  db_price_map: contextData.db_price_map,
  db_stock_map: contextData.db_stock_map,
  product_count: contextData.product_count
}}];

