// Retry counter'ı artır ve hata bilgisini geri gönder
const prev = $input.first().json;
return [{ json: {
  message: prev.original_message,
  customer_id: prev.customer_id,
  customer_group: prev.customer_group,
  is_admin: prev.is_admin,
  image: null,
  search_term: prev.search_term,
  intent: prev.intent,
  keywords: [],
  retry_count: (prev.retry_count || 0) + 1,
  max_retries: prev.max_retries || 3,
  validation_errors: prev.errors || [],
  timestamp: new Date().toISOString()
}}];

